prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName (COUNT(DISTINCT ?msg) AS ?messageCount) WHERE {
  ?model a bboExt:Model ;
         tai:originalId "2f572d235e784b838fa0d7d2a56748ab" .
  ?choreo tai:belongsTo ?model .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name ?taskName .

  ?mf a bboExt:MessageFlow ;
      tai:belongsTo ?choreo ;
      bboExt:sourceRef ?srcRef ;
      bboExt:targetRef ?tgtRef .

  # link message flow endpoints to task IDs
  FILTER(STRENDS(STR(?task), ?srcRef) || STRENDS(STR(?task), ?tgtRef))

  OPTIONAL { ?mf bboExt:messageRef ?msg . }
}
GROUP BY ?task ?taskName
HAVING (COUNT(DISTINCT ?msg) > 1)
ORDER BY DESC(?messageCount)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo (COUNT(DISTINCT ?mf) AS ?messageFlows) WHERE {
  ?model a bboExt:Model ;
         tai:originalId "2f572d235e784b838fa0d7d2a56748ab" ;
         tai:belongsTo ?org .
  ?model tai:belongsTo ?org .
  ?choreo tai:belongsTo ?model .
  ?mf a bboExt:MessageFlow ;
      tai:belongsTo ?choreo .
}
GROUP BY ?choreo
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?elem ?type ?name WHERE {
  ?model a bboExt:Model ;
         tai:originalId "2f572d235e784b838fa0d7d2a56748ab" ;
         tai:belongsTo ?org .
  ?elem tai:belongsTo ?choreo .
  ?choreo tai:belongsTo ?model .
  ?elem a ?type .
  OPTIONAL { ?elem bbo:name ?name . }
  FILTER(?type IN (bboExt:MessageFlow, bboExt:Message, bboExt:Association))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?task ?taskName ?msg ?msgName (COUNT(DISTINCT ?link) AS ?linkCount) WHERE {
  ?model a bboExt:Model ;
         tai:originalId "2f572d235e784b838fa0d7d2a56748ab" ;
         tai:belongsTo ?org .
  ?model tai:belongsTo ?org .

  ?choreo tai:belongsTo ?model .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name ?taskName .

  # try to find direct references from tasks to messages
  OPTIONAL {
    ?link ?p ?msg .
    ?link a bboExt:MessageFlow .
  }

  # message reference properties on MessageFlow / other links
  OPTIONAL {
    ?mf a bboExt:MessageFlow ;
        tai:belongsTo ?choreo ;
        ( bboExt:messageRef ?msgId || bboExt:messageRef ?msgId ).
    ?mf bboExt:messageRef ?msgId .
    FILTER(STRENDS(STR(?msg), ?msgId))
  }

  OPTIONAL {
    ?task bboExt:messageRef ?msgId2 .
    FILTER(STRENDS(STR(?msg), ?msgId2))
  }

  ?msg a bboExt:Message ;
       tai:belongsTo ?choreo ;
       bbo:name ?msgName .

  FILTER( EXISTS {
    { ?task bboExt:messageRef ?anyMsgRef . }
    UNION
    { ?mf bboExt:messageRef ?anyMsgRef . FILTER(STRENDS(STR(?msg), ?anyMsgRef)) }
    UNION
    { ?anyLink ?anyP ?anyMsg . FILTER(?anyMsg = ?msg) }
  })
}
GROUP BY ?task ?taskName ?msg ?msgName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName (COUNT(DISTINCT ?msg) AS ?messageCount) WHERE {
  ?model a bboExt:Model ;
         tai:originalId "2f572d235e784b838fa0d7d2a56748ab" ;
         tai:belongsTo ?org .
  ?choreo tai:belongsTo ?model .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name ?taskName .

  # Most reliable: if there are MessageFlow links, they should carry messageRef
  OPTIONAL {
    ?mf a bboExt:MessageFlow ;
        tai:belongsTo ?choreo ;
        bboExt:messageRef ?msgId .
    ?msg a bboExt:Message ;
         tai:belongsTo ?choreo ;
         bbo:name ?msgName .
    FILTER(STRENDS(STR(?msg), ?msgId))

    # connect the MF endpoints to this task via string refs
    FILTER(STRENDS(STR(?task), STR(?srcTaskId)))
    # try matching by source/target refs if present
    OPTIONAL { ?mf bboExt:sourceRef ?srcTaskId . }
    OPTIONAL { ?mf bboExt:targetRef ?tgtTaskId . }
    FILTER(
      (BOUND(?srcTaskId) && STRENDS(STR(?task), ?srcTaskId))
      ||
      (BOUND(?tgtTaskId) && STRENDS(STR(?task), ?tgtTaskId))
    )
  }

  # Alternative direct property from task to message IDs
  OPTIONAL {
    ?task bboExt:messageRef ?msgId2 .
    ?msg a bboExt:Message ;
         tai:belongsTo ?choreo ;
         bbo:name ?msgName2 .
    FILTER(STRENDS(STR(?msg), ?msgId2))
  }

  ?msg a bboExt:Message .
  FILTER(?msg = ?msg)  
}
GROUP BY ?task ?taskName
HAVING (COUNT(DISTINCT ?msg) > 1)
LIMIT 25
